function openNclose(t){t.target.parentNode.classList.toggle("faq__questions__item--is-open")}function removeActiveButton(){var e=document.querySelectorAll("[data-tab-button]");for(let t=0;t<e.length;t++)e[t].classList.remove("info__container__tabs__button--is-active")}function HideAllTabs(){var e=document.querySelectorAll("[data-tab-id]");for(let t=0;t<e.length;t++)e[t].classList.remove("info__container__content__box--is-active")}document.addEventListener("DOMContentLoaded",function(){var e=document.querySelectorAll("[data-tab-button]"),n=document.querySelectorAll("[data-faq-question]");for(let t=0;t<e.length;t++)e[t].addEventListener("click",function(t){var e=t.target.dataset.tabButton,e=document.querySelector(`[data-tab-id=${e}]`);HideAllTabs(),e.classList.add("info__container__content__box--is-active"),removeActiveButton(),t.target.classList.add("info__container__tabs__button--is-active")});for(let t=0;t<n.length;t++)n[t].addEventListener("click",openNclose)});